#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int accountNumber;
        double balance, interestRate;
        if (scanf("%d %lf", &accountNumber, &balance) != 2) return 0;
        scanf("%lf", &interestRate); // not used
        int N;
        scanf("%d", &N);
        char op[10];
        double amt;
        for (int i = 0; i < N; ++i) {
            scanf("%s %lf", op, &amt);
            if (strcmp(op, "deposit") == 0) {
                balance += amt;
                printf("%.1f\n", balance);
            } else { // withdraw
                if (amt <= balance && (balance - amt) >= 500.0) {
                    balance -= amt;
                    printf("%.1f\n", balance);
                } else {
                    printf("Insufficient balance\n");
                }
            }
        }
    }
    return 0;
}

