import java.util.*;

class BankAccount {
    protected int accountNumber;
    protected double balance;
    public BankAccount(int accountNumber, double balance) {
        this.accountNumber = accountNumber;
        this.balance = balance;
    }
    public void deposit(double amount) {
        balance += amount;
        System.out.printf("%.1f\n", balance);
    }
    public void withdraw(double amount) {
        if (amount <= balance) {
            balance -= amount;
            System.out.printf("%.1f\n", balance);
        } else {
            System.out.println("Insufficient balance");
        }
    }
}

class SavingsAccount extends BankAccount {
    private double interestRate;
    public SavingsAccount(int accountNumber, double balance, double interestRate) {
        super(accountNumber, balance);
        this.interestRate = interestRate;
    }
    @Override
    public void withdraw(double amount) {
        if (amount <= balance && (balance - amount) >= 500.0) {
            balance -= amount;
            System.out.printf("%.1f\n", balance);
        } else {
            System.out.println("Insufficient balance");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int accNo = sc.nextInt();
            double bal = sc.nextDouble();
            double rate = sc.nextDouble(); // not used in logic
            int N = sc.nextInt();
            SavingsAccount sa = new SavingsAccount(accNo, bal, rate);
            for (int i = 0; i < N; ++i) {
                String op = sc.next();
                double amt = sc.nextDouble();
                if (op.equals("deposit")) {
                    sa.deposit(amt);
                } else if (op.equals("withdraw")) {
                    sa.withdraw(amt);
                }
            }
        }
        sc.close();
    }
}

